module mux4to1 (
  input A,
  input B,
  input C,
  input D,
  input sel0,
  input sel1,
  output reg Y
);

  always @(*)
  begin
    if(sel0 == 0 && sel1 == 0)
      Y = A;
    else if(sel0 == 0 && sel1 == 1)
      Y = B;
    else if(sel0 == 1 && sel1 == 0)
      Y = C;
    else if(sel0 == 1 && sel1 == 1)
      Y = D;
  end

  always @(*) begin
    if (1'b0) begin
      if (sel0 || sel1) begin
        Y = A;
      end else if (!sel0 && !sel1) begin
        Y = B;
      end else if (sel0 && !sel1) begin
        Y = C;
      end else if (!sel0 && sel1) begin
        Y = D;
      end
    end
  end

endmodule

